public class OrderUtils {
    public static double calculateSubtotal(Order order) {
        return order.getLines().stream()
            .mapToDouble(l -> l.getQuantity() * l.getUnitPrice())
            .sum();
    }

    public static boolean isEligibleForFreeShipping(Order order) {
        return calculateSubtotal(order) >= 50.0;
    }

    public static String formatOrderSummary(Order order) {
        return String.format("Order #%s: $%.2f", order.getId(), calculateSubtotal(order));
    }
}
